const raw = $input.first().json;
const input = Array.isArray(raw) ? raw[0] : raw;

const sessionId = String(
  input.sessionId ||
  input.body?.sessionId ||
  input.chat?.sessionId ||
  input.metadata?.sessionId ||
  "test-sem-session"
);

const chatInput = String(
  input.chatInput ??
  input.message ??
  input.text ??
  input.body?.chatInput ??
  ""
).trim();

function phoneFromSessionId(value) {
  const raw = String(value || "");

  // Pega apenas números do sessionId e usa os 18 primeiros.
  // Resultado final sempre: 99 + 18 dígitos = 20 caracteres.
  let digits = raw.replace(/\D/g, "");

  digits = digits.padEnd(18, "0").slice(0, 18);

  return `99${digits}`;
}

const phone = phoneFromSessionId(sessionId);

if (!/^99\d{18}$/.test(phone) || phone.length !== 20) {
  throw new Error(`phone_teste_invalido: esperado 20 caracteres começando com 99, recebido ${phone}`);
}

const nowIso = new Date().toISOString();
const currentMessageId = Number(input.message_id || input.messageId || Date.now());

// Fonte única dos cães.
// Nada de campo solto tipo cao_nome, cao_raca, cao_sexo etc.
const caesJson = Array.isArray(input.caes_json)
  ? input.caes_json
  : [];

const resumoLead = {
  tutor_nome: "",
  tutor_telefone: phone,
  email_tutor: "",

  quantidade_caes: caesJson.length,
  caes_json: caesJson,

  unidade_preferida: "nao_definida",
  servico_interesse: "nao_definido",
  periodo_desejado: "",
  data_desejada: "",
  data_checkin_desejada: "",
  data_checkout_desejada: "",

  origem_lead: "anuncio_whatsapp",
  origem_detalhada: "chat_n8n_teste",

  comprovante_recebido: false,
  tipo_comprovante: "nao_informado",
  arquivo_comprovante_referencia: "",
  data_hora_avaliacao: "",
  data_hora_pre_reserva: "",
  pre_reserva_criada: false,
  responsavel_humano: "",
  observacoes: ""
};

const chatHistoryUuid = `test:bruna:session:${sessionId}:phone:${phone}`.slice(0, 100);

return [
  {
    json: {
      run_mode: "sandbox",
      origem_execucao: "chat_n8n_teste",
      action: input.action || "sendMessage",
      sessionId,
      chatInput,

      lead: {
        phone,
        chat_history_uuid: chatHistoryUuid
      },

      chatwoot: {
        account_id: 990001,
        inbox_id: 990001,
        conversation_id: Number(String(phone).slice(-9)),
        contact_id: Number(String(phone).slice(-8)),
        message_id: currentMessageId,
        labels: ["teste-bruna", "chat-n8n"],
        event: "message_created",
        system_event: "MESSAGE_RECEIVED"
      },

      message: {
        content: chatInput,
        message_modality: "text_only",
        has_text: chatInput.length > 0,
        has_attachment: false,
        data_url: "",
        current_message_id: currentMessageId,
        history_for_crm: "",
        last_bruna_message_before_current_block: ""
      },

      inputs: {
        is_first_turn: true,

        // Hints operacionais ficam neutros neste node.
        // Interpretação semântica deve acontecer no Analista CRM.
        precisa_responder_preco: false,
        precisa_responder_localizacao: false,
        precisa_responder_visita_material: false,
        deve_priorizar_base_conhecimento: false,

        resumo_lead: resumoLead
      },

      memory: {
        phone,
        chat_history_uuid: chatHistoryUuid,
        nome_tutor: "",
        email_tutor: "",
        quantidade_caes: caesJson.length,
        caes_json: caesJson,
        unidade_preferida: "nao_definida",
        servico_interesse: "nao_definido",
        origem_lead: "anuncio_whatsapp",
        origem_detalhada: "chat_n8n_teste",
        status_lead: "NOVO_LEAD",
        ultima_intencao: "",
        evento_sistema_atual: "",
        resumo_lead_json: resumoLead
      },

      config_bruna_modelo: {},
      criado_em_teste: nowIso
    }
  }
];

function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function firstItem(nodeName) {
  try {
    return $(nodeName).first().json;
  } catch (e) {
    return {};
  }
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function isFilled(value) {
  return value !== undefined && value !== null && value !== "";
}

function firstFilled(...values) {
  for (const value of values) {
    if (isFilled(value)) return value;
  }

  return "";
}

function firstFilledOr(fallback, ...values) {
  const value = firstFilled(...values);
  return isFilled(value) ? value : fallback;
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = String(value || "").trim().toLowerCase();

  if (["1", "true", "sim", "yes"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no"].includes(text)) return false;

  return false;
}

function firstBool(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== "") {
      return toBool(value);
    }
  }

  return false;
}

function normalizeEnum(value, allowed, fallback) {
  const v = String(value || "").trim();
  return allowed.includes(v) ? v : fallback;
}

function publicFacingText(value) {
  return String(value || "")
    .replace(/pitua[cç]u/gi, "Patamares")
    .replace(/nunca use Patamares\.?/gi, "")
    .replace(/não use Patamares\.?/gi, "")
    .replace(/nao use Patamares\.?/gi, "")
    .replace(/\s{2,}/g, " ")
    .trim();
}

function publicFacingObject(value) {
  if (Array.isArray(value)) {
    return value.map(publicFacingObject);
  }

  if (isObject(value)) {
    const out = {};
    for (const [key, item] of Object.entries(value)) {
      out[key] = publicFacingObject(item);
    }
    return out;
  }

  if (typeof value === "string") {
    return publicFacingText(value);
  }

  return value;
}

function normalizeRegrasRaca(value) {
  const regra = isObject(value) ? value : {};

  if (!Object.keys(regra).length) return {};

  return {
    status_raca: normalizeEnum(
      regra.status_raca,
      [
        "sem_raca_informada",
        "precisa_confirmar_raca",
        "bloqueado_potencial_dano",
        "raca_ok"
      ],
      "sem_raca_informada"
    ),
    raca_canonica: publicFacingText(regra.raca_canonica),
    porte_classificado: normalizeEnum(
      regra.porte_classificado,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),
    aceita_auauzin: regra.aceita_auauzin === true,
    potencial_dano: regra.potencial_dano === true,
    raca_encontrada: regra.raca_encontrada === true,
    deve_confirmar_raca: regra.deve_confirmar_raca === true,
    decisao_raca_conclusiva: regra.decisao_raca_conclusiva === true,
    precisa_confirmacao_antes_decisao: regra.precisa_confirmacao_antes_decisao === true,
    pode_seguir_amaralina_por_raca: regra.pode_seguir_amaralina_por_raca === true,
    pode_seguir_auauzin_por_raca: regra.pode_seguir_auauzin_por_raca === true,
    motivo_raca: publicFacingText(regra.motivo_raca),
    escopo_decisao: "por_cao"
  };
}

function emptyDog() {
  return {
    nome: "",
    idade_anos: "",
    idade_texto: "",
    raca: "",
    raca_canonica: "",
    porte: "nao_definido",
    sexo: "nao_informado",
    castrado: "nao_informado",
    no_cio: "nao_informado",
    vacinas_ok: "nao_informado",
    antipulgas_ok: "nao_informado",
    vermifugacao_ok: "nao_informado",
    perfil_comportamental: "nao_informado",
    comportamento_observacoes: "",
    possui_relatorio_veterinario: "nao_informado",
    observacoes: "",
    regras_raca: {}
  };
}

function normalizeDog(dog = {}) {
  const regrasRaca = isObject(dog.regras_raca)
    ? normalizeRegrasRaca(dog.regras_raca)
    : {};

  return {
    ...emptyDog(),

    nome: publicFacingText(dog.nome),
    idade_anos: String(dog.idade_anos || ""),
    idade_texto: publicFacingText(dog.idade_texto),
    raca: publicFacingText(dog.raca),
    raca_canonica: publicFacingText(dog.raca_canonica),

    porte: normalizeEnum(
      dog.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo: normalizeEnum(
      dog.sexo,
      ["macho", "femea", "nao_informado"],
      "nao_informado"
    ),

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: normalizeEnum(
      dog.no_cio,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: publicFacingText(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: publicFacingText(dog.observacoes),
    regras_raca: regrasRaca
  };
}

function normalizeDogs(value) {
  const parsed = parseMaybeJson(value, []);

  if (!Array.isArray(parsed)) return [];

  return parsed
    .filter(dog => dog && typeof dog === "object")
    .map(normalizeDog);
}

function getLatestMessageByType(historico, tipos) {
  const allowed = Array.isArray(tipos) ? tipos : [tipos];

  const ordered = [...historico].sort((a, b) => {
    const da = new Date(a.criado_em || 0).getTime() || 0;
    const db = new Date(b.criado_em || 0).getTime() || 0;
    return da - db;
  });

  const last = [...ordered]
    .reverse()
    .find(h => allowed.includes(h.tipo_registro) && h.mensagem_texto);

  return publicFacingText(last?.mensagem_texto || "");
}

function extractLastQuestionOrRequest(text) {
  const value = publicFacingText(text);

  if (!value) return "";

  const sentences = value
    .match(/[^.!?]+[.!?]?/g)
    ?.map(s => s.trim())
    .filter(Boolean) || [];

  const requestPattern = /(\?|pode me|me informa|me informar|me conta|me contar|preciso saber|tamb[eé]m preciso saber|confirma|confirmar|você consegue|voce consegue)/i;

  for (let i = sentences.length - 1; i >= 0; i--) {
    if (requestPattern.test(sentences[i])) {
      return sentences[i];
    }
  }

  return "";
}

function normalizeUnidadesConfig(unidades = {}) {
  const source = isObject(unidades) ? unidades : {};

  const amaralina = {
    ...(isObject(source.amaralina) ? source.amaralina : {}),
    ...(isObject(source.auau_amaralina) ? source.auau_amaralina : {})
  };

  const auauzin = isObject(source.auauzin_patamares)
    ? source.auauzin_patamares
    : {};

  return publicFacingObject({
    amaralina: {
      ...amaralina,
      nome: firstFilled(amaralina.nome, "AuAu Creche Canina Amaralina"),
      nome_comercial: firstFilled(amaralina.nome_comercial, "AuAu Amaralina"),
      endereco: firstFilled(
        amaralina.endereco,
        "Av. Manoel Dias da Silva, 285 - Amaralina, Salvador - BA"
      ),
      telefone: firstFilled(amaralina.telefone, "(71) 99678-2627"),
      instagram: firstFilled(amaralina.instagram, "@auaucrechecanina"),
      aceita_portes: Array.isArray(amaralina.aceita_portes)
        ? amaralina.aceita_portes
        : ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"]
    },
    auauzin_patamares: {
      ...auauzin,
      nome: "AuAuzin Patamares",
      nome_comercial: "AuAuzin Patamares",
      endereco: "Av. Prof. Pinto de Aguiar, 317 - Patamares, Salvador - BA",
      telefone: firstFilled(auauzin.telefone, "71 9 8858-6565"),
      instagram: firstFilled(auauzin.instagram, "@auaucrechecanina"),
      aceita_portes: Array.isArray(auauzin.aceita_portes)
        ? auauzin.aceita_portes
        : ["mini", "pequeno"],
      instrucao_modelo:
        "No atendimento ao lead, use sempre o nome comercial AuAuzin Patamares. Se precisar informar endereço, use: Av. Prof. Pinto de Aguiar, 317 - Patamares, Salvador - BA."
    }
  });
}

function sanitizeConfigBrunaModelo(config = {}) {
  const allowedKeys = [
    "guias",
    "unidades",
    "microcopy",
    "taxonomia",
    "elegibilidade",
    "handoff_humano",
    "multiplos_caes",
    "politica_preco",
    "precos_servicos",
    "identidade_bruna",
    "comportamento_cao",
    "pagamento_avaliacao",
    "campos_minimos_antes_pix",
    "frequencia_creche_hotel",
    "respostas_compostas"
  ];

  const out = {};

  for (const key of allowedKeys) {
    if (config[key] !== undefined) {
      out[key] = publicFacingObject(config[key]);
    }
  }

  out.unidades = normalizeUnidadesConfig(out.unidades || {});

  if (out.pagamento_avaliacao) {
    delete out.pagamento_avaliacao.pix_tipo;
    delete out.pagamento_avaliacao.pix_chave;
    delete out.pagamento_avaliacao.pix_recebedor;
    delete out.pagamento_avaliacao.cnpj;
    delete out.pagamento_avaliacao.recebedor;
    delete out.pagamento_avaliacao.dados_bancarios;
  }

  out.multiplos_caes = {
    ...(out.multiplos_caes || {}),
    ativo: true,
    campo_quantidade: "quantidade_caes",
    campo_array_canonico: "inputs.caes_json",
    campo_array_memoria: "inputs.caes_json",
    campo_regras_raca: "inputs.caes_json[].regras_raca",
    evitar_assumir_pet_unico: true,
    sempre_preservar_array_existente: true,
    instrucao_modelo:
      "A fonte única dos cães neste payload é inputs.caes_json. Não procure cães em memory.caes_json, resumo_lead.caes_json ou na raiz. Não crie campos soltos cao_nome, cao_raca, cao_sexo, cao_castrado ou similares. As regras de raça, quando existirem, ficam dentro de cada cão em inputs.caes_json[].regras_raca. A decisão de raça é sempre por cão, nunca global para o lead inteiro."
  };

  out.campos_minimos_antes_pix = {
    ...(out.campos_minimos_antes_pix || {}),
    obrigatorios: [
      "servico_interesse",
      "inputs.caes_json[].nome",
      "inputs.caes_json[].idade_anos_ou_idade_texto",
      "inputs.caes_json[].raca",
      "inputs.caes_json[].sexo",
      "inputs.caes_json[].perfil_comportamental",
      "inputs.caes_json[].vacinas_ok",
      "inputs.caes_json[].antipulgas_ok",
      "inputs.caes_json[].vermifugacao_ok"
    ],
    condicionais: [
      {
        campo: "inputs.caes_json[].castrado",
        quando: "inputs.caes_json[].sexo=macho AND inputs.caes_json[].idade>=8_meses"
      },
      {
        campo: "confirmar_raca_do_cao",
        quando: "inputs.caes_json[].regras_raca.status_raca=precisa_confirmar_raca"
      },
      {
        campo: "inputs.caes_json[].possui_relatorio_veterinario",
        quando: "inputs.caes_json[].idade>=10_anos"
      }
    ],
    bloqueios_antes_pix: [
      {
        campo: "inputs.caes_json[].regras_raca.status_raca",
        quando: "bloqueado_potencial_dano",
        escopo: "por_cao"
      },
      {
        campo: "inputs.caes_json[].regras_raca.precisa_confirmacao_antes_decisao",
        quando: "true",
        escopo: "por_cao"
      }
    ],
    exige_aceite_explicito_avaliacao: true,
    nunca_pedir_pix_quando: [
      "primeira_mensagem",
      "lead_pediu_preco",
      "lead_pediu_humano",
      "campos_minimos_faltantes",
      "lead_pesquisando",
      "duvida_de_raca_ou_elegibilidade",
      "qualquer_cao_com_inputs.caes_json[].regras_raca.status_raca=precisa_confirmar_raca",
      "qualquer_cao_com_inputs.caes_json[].regras_raca.status_raca=bloqueado_potencial_dano"
    ]
  };

  out.comportamento_cao = {
    ...(out.comportamento_cao || {}),
    campo_canonico: "inputs.caes_json[].perfil_comportamental",
    campo_observacoes: "inputs.caes_json[].comportamento_observacoes",
    pergunta_preferida:
      out.comportamento_cao?.pergunta_preferida ||
      out.comportamento_cao?.pergunta_unica ||
      "Ele convive bem com outros cães ou tem alguma reatividade que a equipe precise saber?",
    valores_permitidos: [
      "nao_informado",
      "tranquilo",
      "sociavel",
      "seletivo",
      "reativo_leve",
      "reativo_alto",
      "agressivo"
    ],
    nao_usar_perguntas_separadas: [
      "Ele é sociável?",
      "Ele é reativo?"
    ]
  };

  return publicFacingObject(out);
}

const start = JSON.parse(JSON.stringify(firstItem("Normaliza Entrada Teste")));

start.inputs = start.inputs || {};
start.inputs.resumo_lead = start.inputs.resumo_lead || {};
start.message = start.message || {};
start.lead = start.lead || {};
start.chatwoot = start.chatwoot || {};

start.chatInput = publicFacingText(start.chatInput);
start.message.content = publicFacingText(start.message.content || start.chatInput || "");

const memoryRow = firstItem("Buscar Memória Bruna");
const historyRow = firstItem("Buscar Histórico Recente");
const configRow = firstItem("Buscar Config Bruna Modelo");

const memory = parseMaybeJson(memoryRow.memory_json, {});
const historico = parseMaybeJson(historyRow.historico_json, []);

const configBrunaCompleta = parseMaybeJson(
  configRow.config_bruna_modelo ||
  configRow.config_bruna ||
  configRow.regra_valor ||
  {},
  {}
);

const configBrunaModelo = sanitizeConfigBrunaModelo(configBrunaCompleta);

const resumoMemory = parseMaybeJson(memory.resumo_lead_json, {});

const dogsFromMemory = normalizeDogs(memory.caes_json);
const dogsFromResumoMemory = normalizeDogs(resumoMemory.caes_json);
const dogsFromStart = normalizeDogs(start.inputs.caes_json);
const dogsFromStartResumo = normalizeDogs(start.inputs.resumo_lead.caes_json);

const caesJson =
  dogsFromMemory.length ? dogsFromMemory :
  dogsFromResumoMemory.length ? dogsFromResumoMemory :
  dogsFromStart.length ? dogsFromStart :
  dogsFromStartResumo.length ? dogsFromStartResumo :
  [];

const deveRepassarHumanoAtual =
  firstBool(memory.deve_repassar_humano) ||
  memory.status_lead === "TRANSFERIDO_FLAVIA";

const unidadePreferida = normalizeEnum(
  firstFilledOr(
    "nao_definida",
    memory.unidade_preferida,
    resumoMemory.unidade_preferida,
    start.inputs.unidade_preferida,
    start.inputs.resumo_lead.unidade_preferida
  ),
  ["amaralina", "auauzin_patamares", "nao_definida"],
  "nao_definida"
);

const servicoInteresse = normalizeEnum(
  firstFilledOr(
    "nao_definido",
    memory.servico_interesse,
    resumoMemory.servico_interesse,
    start.inputs.servico_interesse,
    start.inputs.resumo_lead.servico_interesse
  ),
  ["creche", "hotel", "creche_e_hotel", "visita", "nao_definido"],
  "nao_definido"
);

const resumoLeadSemCaes = {
  tutor_nome: publicFacingText(firstFilled(
    memory.nome_tutor,
    resumoMemory.tutor_nome,
    start.inputs.resumo_lead.tutor_nome
  )),

  tutor_telefone: firstFilled(
    start.lead.phone,
    memory.phone,
    resumoMemory.tutor_telefone,
    start.inputs.resumo_lead.tutor_telefone
  ),

  email_tutor: firstFilled(
    memory.email_tutor,
    resumoMemory.email_tutor,
    start.inputs.resumo_lead.email_tutor
  ),

  quantidade_caes: caesJson.length,

  unidade_preferida: unidadePreferida,
  servico_interesse: servicoInteresse,

  periodo_desejado: publicFacingText(firstFilled(
    memory.periodo_desejado,
    resumoMemory.periodo_desejado,
    start.inputs.periodo_desejado,
    start.inputs.resumo_lead.periodo_desejado
  )),

  data_desejada: firstFilled(
    memory.data_desejada,
    resumoMemory.data_desejada,
    start.inputs.data_desejada,
    start.inputs.resumo_lead.data_desejada
  ),

  data_checkin_desejada: firstFilled(
    memory.data_checkin_desejada,
    resumoMemory.data_checkin_desejada,
    start.inputs.data_checkin_desejada,
    start.inputs.resumo_lead.data_checkin_desejada
  ),

  data_checkout_desejada: firstFilled(
    memory.data_checkout_desejada,
    resumoMemory.data_checkout_desejada,
    start.inputs.data_checkout_desejada,
    start.inputs.resumo_lead.data_checkout_desejada
  ),

  origem_lead: firstFilledOr(
