function enumValue(value, allowed, fallback, path, aliasGroup = "", previous = "") {
  const raw = String(value ?? "").trim();

  if (!raw) {
    return allowed.includes(previous) ? previous : fallback;
  }

  if (allowed.includes(raw)) return raw;

  const alias = ALIASES[aliasGroup]?.[norm(raw)];
  if (alias && allowed.includes(alias)) {
    addWarning(path, raw, alias, "enum_normalizado_por_alias");
    return alias;
  }

  if (allowed.includes(previous)) {
    addWarning(path, raw, previous, "enum_invalido_preservado_valor_anterior");
    return previous;
  }

  addWarning(path, raw, fallback, "enum_invalido_usado_fallback");
  return fallback;
}

