function hasDogData(dog) {
  const empty = emptyDog();

  return Object.keys(empty).some(key => {
    if (key === "regras_raca") {
      return isObject(dog[key]) && Object.keys(dog[key]).length > 0;
    }

    return JSON.stringify(dog[key]) !== JSON.stringify(empty[key]);
  });
}

function normalizeDogs(value) {
  const parsed = parseMaybeJson(value, []);
  if (!Array.isArray(parsed)) return [];

  return parsed
    .filter(item => item && typeof item === "object")
    .map((dog, index) => normalizeDog(dog, {}, index))
    .filter(hasDogData);
}

function dogScore(a, b) {
  let score = 0;

  const nameA = norm(a.nome);
  const nameB = norm(b.nome);
  const raceA = norm(a.raca_canonica || a.raca);
  const raceB = norm(b.raca_canonica || b.raca);
  const ageA = norm(a.idade_anos || a.idade_texto);
  const ageB = norm(b.idade_anos || b.idade_texto);

  if (nameA && nameB && nameA === nameB) score += 10;
  if (raceA && raceB && raceA === raceB) score += 3;
  if (ageA && ageB && ageA === ageB) score += 2;
  if (a.sexo !== "nao_informado" && b.sexo !== "nao_informado" && a.sexo === b.sexo) score += 1;

  return score;
}

function isMeaningfulDogField(key, value) {
  if (value === undefined || value === null || value === "") return false;
  if (key === "regras_raca") return isObject(value) && Object.keys(value).length > 0;
  if (key === "porte") return value !== "nao_definido";

  if ([
    "sexo",
    "castrado",
    "no_cio",
    "vacinas_ok",
    "antipulgas_ok",
    "vermifugacao_ok",
    "perfil_comportamental",
    "possui_relatorio_veterinario"
  ].includes(key)) {
    return value !== "nao_informado";
  }

  return true;
}

function mergeDog(baseDog, nextDog, index = 0) {
  const base = normalizeDog(baseDog, {}, index);
  const next = normalizeDog(nextDog, base, index);
  const out = { ...base };

  for (const key of Object.keys(emptyDog())) {
    if (isMeaningfulDogField(key, next[key])) {
      out[key] = next[key];
    }
  }

  return normalizeDog(out, {}, index);
}

function mergeDogs(baseList, nextList) {
  const base = normalizeDogs(baseList);
  const next = normalizeDogs(nextList);

  if (!base.length) return next;
  if (!next.length) return base;

  const out = [...base];

  for (const dog of next) {
    let bestIndex = -1;
    let bestScore = 0;

    for (let i = 0; i < out.length; i++) {
      const score = dogScore(out[i], dog);

      if (score > bestScore) {
        bestScore = score;
        bestIndex = i;
      }
    }

    if (bestIndex >= 0 && bestScore >= 3) {
      out[bestIndex] = mergeDog(out[bestIndex], dog, bestIndex);
    } else {
      out.push(normalizeDog(dog, {}, out.length));
    }
  }

  return out.map((dog, index) => normalizeDog(dog, {}, index)).filter(hasDogData);
}

function cleanSummary(value = {}) {
  const out = isObject(value) ? { ...value } : {};

  delete out.caes_json;
  delete out.quantidade_caes;

  return out;
}

