function slugName(value) {
  return String(value || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "") || "cao";
}

function idadeEmAnos(dog = {}) {
  const idadeAnos = String(dog.idade_anos || "").replace(",", ".").trim();
  const matchAnos = idadeAnos.match(/\d+(\.\d+)?/);

  if (matchAnos) return Number(matchAnos[0]);

  const idadeTexto = String(dog.idade_texto || "").toLowerCase();

  const matchMeses = idadeTexto.match(/(\d+)\s*(mes|meses)/i);
  if (matchMeses) return Number(matchMeses[1]) / 12;

  const matchTextoAnos = idadeTexto.match(/(\d+)\s*(ano|anos)/i);
  if (matchTextoAnos) return Number(matchTextoAnos[1]);

  return null;
}

function isMachoAdultoSemCastracao(dog = {}) {
  const sexo = String(dog.sexo || "").toLowerCase();
  const castrado = String(dog.castrado || "").toLowerCase();
  const idade = idadeEmAnos(dog);

  return sexo === "macho" && idade !== null && idade >= 8 / 12 && castrado === "nao_informado";
}

