function cleanText(value) {
  return String(value ?? "").trim();
}

function norm(value) {
  return cleanText(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function dogHasRealIdentity(dog = {}) {
  if (!isObject(dog)) return false;

  return Boolean(
    cleanText(dog.nome) ||
    cleanText(dog.raca) ||
    cleanText(dog.raca_canonica) ||
    cleanText(dog.idade_anos) ||
    cleanText(dog.idade_texto) ||
    ["macho", "femea"].includes(norm(dog.sexo))
  );
}

function dogKey(dog = {}) {
  const nome = norm(dog.nome);
  if (nome) return `nome:${nome}`;

  return [
    norm(dog.raca_canonica || dog.raca),
    norm(dog.idade_anos || dog.idade_texto),
    norm(dog.sexo)
  ].join("|");
}

function dedupeDogsFinal(dogs = []) {
  const result = [];
  const seen = new Set();

  for (const dog of Array.isArray(dogs) ? dogs : []) {
    if (!dogHasRealIdentity(dog)) continue;

    const key = dogKey(dog);
    if (seen.has(key)) continue;

    seen.add(key);
    result.push({
      ...dog,
      idade_anos: cleanText(dog.idade_anos),
      regras_raca: isObject(dog.regras_raca) ? dog.regras_raca : {}
    });
  }

  return result;
}

