const ctx = JSON.parse(JSON.stringify($json || {}));

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function cleanText(value) {
  return String(value || "").trim();
}

function normalizeSearchValue(value) {
  const text = cleanText(value);

  if (!text) return "";

  const normalized = text
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();

  if (
    normalized === "nao_informado" ||
    normalized === "nao informado" ||
    normalized === "não informado" ||
    normalized === "indefinido" ||
    normalized === "nao_definido" ||
    normalized === "não definido"
  ) {
    return "";
  }

  return text;
}

function normalizeDogForBreedLookup(dog = {}, index = 0) {
  const raca = normalizeSearchValue(dog.raca);
  const racaCanonica = normalizeSearchValue(dog.raca_canonica);

  return {
    dog_index: index,
    nome: cleanText(dog.nome),
    idade_anos: cleanText(dog.idade_anos),
    idade_texto: cleanText(dog.idade_texto),

    // Mantém os dois campos, mas evita "nao_informado" atrapalhar a consulta.
    raca,
    raca_canonica: racaCanonica,

    // Campo auxiliar para a consulta priorizar o melhor texto disponível.
    // Se raca_canonica vier "nao_informado", cai automaticamente para raca.
    raca_busca: racaCanonica || raca,

    porte: cleanText(dog.porte) || "nao_definido",
    sexo: cleanText(dog.sexo) || "nao_informado",
    castrado: cleanText(dog.castrado) || "nao_informado",
    no_cio: cleanText(dog.no_cio) || "nao_informado",
    vacinas_ok: cleanText(dog.vacinas_ok) || "nao_informado",
    antipulgas_ok: cleanText(dog.antipulgas_ok) || "nao_informado",
    vermifugacao_ok: cleanText(dog.vermifugacao_ok) || "nao_informado",
    perfil_comportamental: cleanText(dog.perfil_comportamental) || "nao_informado",
    comportamento_observacoes: cleanText(dog.comportamento_observacoes),
    possui_relatorio_veterinario: cleanText(dog.possui_relatorio_veterinario) || "nao_informado",
    observacoes: cleanText(dog.observacoes)

    // Importante:
    // regras_raca NÃO vai neste payload.
    // A consulta precisa recalcular a regra.
  };
}

function normalizeDogsForBreedLookup(value) {
  const parsed = parseMaybeJson(value, []);

  if (!Array.isArray(parsed)) return [];

  return parsed
    .filter(dog => isObject(dog))
    .map((dog, index) => normalizeDogForBreedLookup(dog, index));
}

