const raw = $input.first().json || {};

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function isNonEmptyObject(value) {
  return isObject(value) && Object.keys(value).length > 0;
}

function firstObject(...values) {
  for (const value of values) {
    if (isNonEmptyObject(value)) return value;
  }
  return {};
}

function cleanString(value) {
  if (value === undefined || value === null) return "";
  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return "";
    }
  }
  return String(value).trim();
}

function normalizeText(value) {
  return cleanString(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function parseJsonFlexible(value) {
  if (value === undefined || value === null) return {};

  if (typeof value === "object") return value;

  let text = String(value).trim();

  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const firstBrace = text.indexOf("{");
  const lastBrace = text.lastIndexOf("}");

  if (firstBrace >= 0 && lastBrace > firstBrace) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    return {
      __parse_error: true,
      __parse_error_message: error.message,
      __raw_text: value
    };
  }
}

function unwrapBrunaOutput(value) {
  const parsed = parseJsonFlexible(value);

  if (!isObject(parsed)) {
    return {
      bruna: {},
      parse_error: true,
      raw_parsed: parsed
    };
  }

  if (parsed.__parse_error === true) {
    return {
      bruna: parsed,
      parse_error: true,
      raw_parsed: parsed
    };
  }

  // Caso 1:
  // O n8n entrega { output: "JSON em string" }
  if (typeof parsed.output === "string") {
    const nested = parseJsonFlexible(parsed.output);

    if (nested.__parse_error === true) {
      return {
        bruna: nested,
        parse_error: true,
        raw_parsed: nested
      };
    }

    if (isObject(nested)) {
      let merged = {
        ...parsed,
        ...nested
      };

      delete merged.output;

      // Caso a string interna ainda venha como { output: {...} }
      if (isObject(nested.output)) {
        merged = {
          ...merged,
          ...nested.output
        };

        delete merged.output;
      }

      return {
        bruna: merged,
        parse_error: false,
        raw_parsed: parsed
      };
    }
  }

  // Caso 2:
  // A Bruna/modelo gerou wrapper parcial:
  // { output: { status_lead, mensagens_resposta }, resumo_lead, proxima_acao... }
  if (isObject(parsed.output)) {
    let merged = {
      ...parsed,
      ...parsed.output
    };

    delete merged.output;

    // Caso raro: { output: { output: {...} } }
    if (isObject(parsed.output.output)) {
      merged = {
        ...merged,
        ...parsed.output.output
      };

      delete merged.output;
    }

    return {
      bruna: merged,
      parse_error: false,
      raw_parsed: parsed
    };
  }

  // Caso 3:
  // Alguns nodes podem retornar { text: "JSON" } ou { response: "JSON" }
  for (const key of ["text", "response", "chatOutput"]) {
    if (typeof parsed[key] === "string") {
      const nested = parseJsonFlexible(parsed[key]);

      if (!nested.__parse_error && isObject(nested)) {
        let merged = {
          ...parsed,
          ...nested
        };

        delete merged[key];

        if (isObject(nested.output)) {
          merged = {
            ...merged,
            ...nested.output
          };

          delete merged.output;
        }

        return {
          bruna: merged,
          parse_error: false,
          raw_parsed: parsed
        };
      }
    }
  }

  // Caso normal:
  // JSON já veio direto na raiz
  return {
    bruna: parsed,
    parse_error: false,
    raw_parsed: parsed
  };
}
function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = normalizeText(value);
  return ["1", "true", "sim", "yes"].includes(text);
}

function enumValue(value, allowed, fallback, path = "") {
  const text = cleanString(value);
  if (allowed.includes(text)) return text;

  if (text && path) {
    warnings.push({
      path,
      raw: text,
      result: fallback,
      reason: "enum_invalido_usado_fallback"
    });
  }

  return fallback;
}

function firstFilled(...values) {
  for (const value of values) {
    const text = cleanString(value);
    if (text !== "") return text;
  }
  return "";
}

function parseArray(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

function normalizeMessages(messages) {
  const arr = Array.isArray(messages) ? messages : [];

  const normalized = arr
    .map(cleanString)
    .filter(Boolean);

  if (normalized.length > 4) {
    warnings.push({
      path: "mensagens_resposta",
      raw: normalized.length,
      result: normalized.length,
      reason: "mais_de_4_mensagens_sem_corte_automatico"
    });
  }

  return normalized;
}

function similarity(a, b) {
  const tokensA = new Set(normalizeText(a).split(" ").filter(Boolean));
  const tokensB = new Set(normalizeText(b).split(" ").filter(Boolean));

  if (!tokensA.size || !tokensB.size) return 0;

  let intersection = 0;

  for (const token of tokensA) {
    if (tokensB.has(token)) intersection++;
  }

  const union = new Set([...tokensA, ...tokensB]).size;
  return union ? intersection / union : 0;
}

function hasRepeatedConfirmation(messages, lastMessage) {
  const joined = normalizeText(messages.join(" "));
  const last = normalizeText(lastMessage);

  const pattern = "obrigada por confirmar";
  const pattern2 = "obrigado por confirmar";

  return (
    (joined.includes(pattern) && last.includes(pattern)) ||
    (joined.includes(pattern2) && last.includes(pattern2))
  );
}

function hasConversationContinuation(messages, flags = {}) {
  if (!messages.length) return false;

  if (
    flags.deve_repassar_humano ||
    flags.deve_encerrar_conversa ||
    flags.deve_solicitar_pagamento
  ) {
    return true;
  }

  const last = cleanString(messages[messages.length - 1]);
  const normalized = normalizeText(last);

  if (last.includes("?")) return true;

  const deadEndPatterns = [
    "fico a disposicao",
    "qualquer duvida estou aqui",
    "quando quiser me avise",
    "estou a disposicao"
  ];

  return !deadEndPatterns.some(pattern => normalized.includes(pattern));
}

function stripDogCopies(obj = {}) {
  if (!isObject(obj)) return {};

  const out = { ...obj };

  delete out.caes_json;
  delete out.quantidade_caes;
  delete out.regras_raca;

  return out;
}

