      motivo_bloqueio_envio: motivoBloqueioEnvio,

      opcoes: base.opcoes || {},

      run_mode: base.run_mode || "prod",
      prompt_version:
        base.prompt_version ||
        previousInputs.versao_regras_negocio ||
        "v8_sem_parser_unwrap_output_parcial",

      raw_bruna_output: rawOutput,

      debug_context: debugContext
    }
  }
];

const ctx = JSON.parse(JSON.stringify($json || {}));

function cleanText(value) {
  return String(value ?? "").trim();
}

function norm(value) {
  return cleanText(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function dogHasRealIdentity(dog = {}) {
  if (!isObject(dog)) return false;

  return Boolean(
    cleanText(dog.nome) ||
    cleanText(dog.raca) ||
    cleanText(dog.raca_canonica) ||
    cleanText(dog.idade_anos) ||
    cleanText(dog.idade_texto) ||
    ["macho", "femea"].includes(norm(dog.sexo))
  );
}

function isBlankDog(dog = {}) {
  if (!isObject(dog)) return true;

  return !dogHasRealIdentity(dog);
}

function dogKey(dog = {}) {
  const nome = norm(dog.nome);
  const raca = norm(dog.raca_canonica || dog.raca);
  const idade = norm(dog.idade_anos || dog.idade_texto);
  const sexo = norm(dog.sexo);

  if (nome) return `nome:${nome}`;

  return [
    `raca:${raca}`,
    `idade:${idade}`,
    `sexo:${sexo}`
  ].join("|");
}

function mergeDog(base = {}, incoming = {}) {
  const out = { ...base };

  for (const [key, value] of Object.entries(incoming || {})) {
    if (key === "regras_raca") continue;

    const valueText = cleanText(value);
    const currentText = cleanText(out[key]);

    if (valueText && !currentText) {
      out[key] = value;
    }
  }

  if (isObject(base.regras_raca) && Object.keys(base.regras_raca).length) {
    out.regras_raca = base.regras_raca;
  } else if (isObject(incoming.regras_raca)) {
    out.regras_raca = incoming.regras_raca;
  } else {
    out.regras_raca = {};
  }

  return out;
}

function sanitizeDogs(dogs = []) {
  const input = Array.isArray(dogs) ? dogs : [];
  const result = [];
  const index = new Map();

  for (const dog of input) {
    if (!isObject(dog)) continue;
    if (isBlankDog(dog)) continue;

    const key = dogKey(dog);

    if (!index.has(key)) {
      index.set(key, result.length);
      result.push(dog);
      continue;
    }

    const pos = index.get(key);
    result[pos] = mergeDog(result[pos], dog);
  }

  return result;
}

ctx.inputs = isObject(ctx.inputs) ? ctx.inputs : {};

ctx.inputs.caes_json = sanitizeDogs(ctx.inputs.caes_json);
ctx.inputs.quantidade_caes = ctx.inputs.caes_json.length;

if (isObject(ctx.inputs.resumo_lead)) {
  delete ctx.inputs.resumo_lead.caes_json;
  delete ctx.inputs.resumo_lead.quantidade_caes;
}

if (isObject(ctx.inputs.resumo_interno_repasse)) {
  delete ctx.inputs.resumo_interno_repasse.caes_json;
  delete ctx.inputs.resumo_interno_repasse.quantidade_caes;
}

return [{ json: ctx }];

